Bash(powershell.exe -NoProfile -ExecutionPolicy Bypass -File - << 'PSEOF'
$script = @"
import { readFileSync } from 'fs';
const raw = readFileSync\('lh-homepage-deep.json', 'utf8'\);
const lhr = JSON.parse\(raw\);
const audits = lhr.audits;
const sep = '='.repeat\(80\);

function printAudit\(id, label\) {
  const a = audits[id];
  if \(!a\) { console.log\('\\n[MISSING] ' + id\); return a; }
  console.log\('\\n' + sep\);
  console.log\(label || id\);
  console.log\('Score: ' + a.score + '  |  Display: ' + \(a.displayValue || 'n/a'\) + '  |  Numeric: ' + \(a.numericValue ?? 'n/a'\) + ' ' + \(a.numericUnit || ''\)\);
  console.log\(sep\);
  return a;
}

console.log\('\\n' + '#'.repeat\(80\)\);
console.log\('  LIGHTHOUSE PERFORMANCE REPORT'\);
console.log\('  URL:', lhr.requestedUrl\);
console.log\('  Fetch time:', lhr.fetchTime\);
console.log\('  Form factor:', lhr.configSettings?.formFactor\);
console.log\('  Throttling:', JSON.stringify\(lhr.configSettings?.throttling, null, 2\)\);
console.log\('  OVERALL SCORE:', \(lhr.categories?.performance?.score * 100\).toFixed\(0\)\);
console.log\('#'.repeat\(80\)\);

console.log\('\\n' + sep\);
console.log\('CORE WEB VITALS'\);
console.log\(sep\);
for \(const id of ['first-contentful-paint', 'largest-contentful-paint', 'total-blocking-time', 'cumulative-layout-shift', 'speed-index', 'interactive', 'max-potential-fid']\) {
  const a = audits[id];
  if \(a\) console.log\('  ' + id.padEnd\(35\) + \(a.displayValue || ''\).padEnd\(12\) + ' score=' + a.score + '  numeric=' + a.numericValue?.toFixed\(1\) + ' ' + \(a.numericUnit || ''\)\);
}

{
  const a = printAudit\('server-response-time', 'SERVER RESPONSE TIME \(TTFB\)'\);
  if \(a?.details?.items\) for \(const item of a.details.items\) {
    console.log\('  URL: ' + item.url\);
    console.log\('  Response time: ' + item.responseTime?.toFixed\(1\) + ' ms'\);
  }
}

console.log\('\\n' + sep\);
console.log\('ALL AUDITS WITH lcp IN THE ID'\);
console.log\(sep\);
for \(const [id, a] of Object.entries\(audits\)\) {
  if \(id.toLowerCase\(\).includes\('lcp'\)\) {
    console.log\('\\n  --- ' + id + ' ---'\);
    console.log\('  Title: ' + a.title\);
    console.log\('  Score: ' + a.score + '  Display: ' + \(a.displayValue || 'n/a'\)\);
    console.log\('  Description: ' + a.description?.slice\(0, 200\)\);
    if \(a.details?.items?.length\) {
      console.log\('  Items \(' + a.details.items.length + '\):'\);
      for \(const item of a.details.items.slice\(0, 5\)\) console.log\('    ' + JSON.stringify\(item\)\);
    }
  }
}

{
  const a = printAudit\('largest-contentful-paint-element', 'LCP ELEMENT DETAILS'\);
  if \(a?.details?.items\) for \(const item of a.details.items\) console.log\(JSON.stringify\(item, null, 2\)\);
  if \(a?.details?.headings\) console.log\('  Headings: ' + JSON.stringify\(a.details.headings\)\);
}

{
  const a = printAudit\('lcp-lazy-loaded', 'LCP LAZY LOADED CHECK'\);
  if \(a?.details?.items\) for \(const item of a.details.items\) console.log\(JSON.stringify\(item, null, 2\)\);
}

{
  const a = printAudit\('prioritize-lcp-image', 'PRIORITIZE LCP IMAGE'\);
  if \(a?.details?.items\) for \(const item of a.details.items\) console.log\(JSON.stringify\(item, null, 2\)\);
  if \(a?.details?.debugData\) console.log\('  Debug data: ' + JSON.stringify\(a.details.debugData, null, 2\)\);
}

{
  const a = printAudit\('critical-request-chains', 'CRITICAL REQUEST CHAINS'\);
  if \(a?.details?.chains\) {
    function walkChain\(node, depth\) {
      for \(const [id, child] of Object.entries\(node\)\) {
        const req = child.request;
        const indent = '  '.repeat\(depth + 1\);
        if \(req\) console.log\(indent + '[' + \(req.transferSize ? \(req.transferSize/1024\).toFixed\(1\)+'kB' : '?'\) + '] ' + req.url?.slice\(0, 120\) + ' \(' + req.startTime?.toFixed\(0\) + '-' + req.endTime?.toFixed\(0\) + 'ms\)'\);
        if \(child.children\) walkChain\(child.children, depth + 1\);
      }
    }
    walkChain\(a.details.chains, 0\);
    const lc = a.details.longestChain;
    if \(lc\) console.log\('\\n  Longest chain: ' + lc.duration?.toFixed\(0\) + ' ms, ' + lc.length + ' requests, ' + \(\(lc.transferSize||0\)/1024\).toFixed\(1\) + ' kB'\);
  }
}

{
  const a = printAudit\('render-blocking-resources', 'RENDER BLOCKING RESOURCES'\);
  if \(a?.details?.items\) {
    console.log\('  Potential savings: ' + a.displayValue\);
    for \(const item of a.details.items\) console.log\('  [' + \(item.totalBytes/1024\).toFixed\(1\) + ' kB, ' + item.wastedMs?.toFixed\(0\) + ' ms wasted] ' + item.url?.slice\(0, 120\)\);
  }
}

{
  const a = printAudit\('mainthread-work-breakdown', 'MAIN THREAD WORK BREAKDOWN'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => y.duration - x.duration\);
    console.log\('  Total: ' + a.numericValue?.toFixed\(0\) + ' ms'\);
    for \(const item of sorted\) {
      const bar = '#'.repeat\(Math.round\(item.duration / 50\)\);
      console.log\('  ' + \(item.groupLabel || item.group || '?'\).padEnd\(30\) + item.duration.toFixed\(0\).padStart\(6\) + ' ms  ' + bar\);
    }
  }
}

{
  const a = printAudit\('bootup-time', 'BOOT-UP TIME \(SCRIPT EVALUATION\)'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => y.total - x.total\);
    console.log\('  Top scripts by total CPU time:'\);
    for \(const item of sorted.slice\(0, 20\)\) {
      console.log\('  ' + \(item.url||'?'\).slice\(0, 90\).padEnd\(92\) + ' total=' + item.total?.toFixed\(0\) + 'ms  scripting=' + item.scripting?.toFixed\(0\) + 'ms  parse=' + item.scriptParseCompile?.toFixed\(0\) + 'ms'\);
    }
  }
}

{
  const a = printAudit\('network-requests', 'NETWORK REQUESTS WATERFALL \(first 30 by endTime\)'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => x.endTime - y.endTime\);
    console.log\('  Total requests: ' + a.details.items.length\);
    console.log\('  ' + '#'.padStart\(3\) + ' ' + 'start'.padStart\(9\) + ' ' + 'end'.padStart\(9\) + ' ' + 'dur'.padStart\(9\) + ' ' + 'xfer'.padStart\(9\) + ' prot  status mimeType                  URL'\);
    for \(const [i, item] of sorted.slice\(0, 30\).entries\(\)\) {
      const start = item.startTime?.toFixed\(0\) || '?';
      const end = item.endTime?.toFixed\(0\) || '?';
      const dur = \(item.endTime - item.startTime\)?.toFixed\(0\) || '?';
      const xfer = item.transferSize ? \(item.transferSize / 1024\).toFixed\(1\) + 'kB' : '?';
      console.log\('  ' + String\(i+1\).padStart\(3\) + ' ' + start.padStart\(9\) + ' ' + end.padStart\(9\) + ' ' + dur.padStart\(9\) + ' ' + xfer.padStart\(9\) + ' ' + \(item.protocol||'?'\).padEnd\(5\) + ' ' + String\(item.statusCode||'?'\).padEnd\(7\) + \(item.mimeType||'?'\).slice\(0,25\).padEnd\(26\) + \(item.url||''\).slice\(0, 100\)\);
    }
  }
}

{
  const a = printAudit\('total-byte-weight', 'TOTAL BYTE WEIGHT'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => y.totalBytes - x.totalBytes\);
    console.log\('  Total: ' + \(a.numericValue / 1024\).toFixed\(0\) + ' kB'\);
    for \(const item of sorted.slice\(0, 20\)\) console.log\('  ' + \(item.totalBytes/1024\).toFixed\(1\).padStart\(8\) + ' kB  ' + \(item.url||''\).slice\(0, 120\)\);
  }
}

{
  const a = printAudit\('diagnostics', 'DIAGNOSTICS'\);
  if \(a?.details?.items?.[0]\) {
    for \(const [k, v] of Object.entries\(a.details.items[0]\)\) console.log\('  ' + k.padEnd\(35\) + v\);
  }
}

{
  const a = printAudit\('unused-javascript', 'UNUSED JAVASCRIPT'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => y.wastedBytes - x.wastedBytes\);
    console.log\('  Potential savings: ' + a.displayValue\);
    for \(const item of sorted.slice\(0, 15\)\) console.log\('  [' + \(item.wastedBytes/1024\).toFixed\(1\) + ' kB wasted of ' + \(item.totalBytes/1024\).toFixed\(1\) + ' kB] ' + \(item.url||''\).slice\(0, 110\)\);
  }
}

{
  const a = printAudit\('unused-css-rules', 'UNUSED CSS'\);
  if \(a?.details?.items\) {
    const sorted = [...a.details.items].sort\(\(x, y\) => y.wastedBytes - x.wastedBytes\);
    console.log\('  Potential savings: ' + a.displayValue\);
    for \(const item of sorted.slice\(0, 10\)\) console.log\('  [' + \(item.wastedBytes/1024\).toFixed\(1\) + ' kB wasted of ' + \(item.totalBytes/1024\).toFixed\(1\) + ' kB] ' + \(item.url||''\).slice\(0, 110\)\);
  }
}

{
  const a = printAudit\('uses-long-cache-ttl', 'EFFICIENT CACHE POLICY'\);
  if \(a?.details?.items\) {
    console.log\('  Resources with short cache TTL: ' + a.details.items.length\);
    for \(const item of a.details.items.slice\(0, 10\)\) console.log\('  [TTL=' + \(item.cacheLifetimeMs ? \(item.cacheLifetimeMs/3600000\).toFixed\(1\)+'h' : 'none'\) + ', ' + \(item.totalBytes/1024\).toFixed\(1\) + 'kB] ' + \(item.url||''\).slice\(0, 110\)\);
  }
}

{
  const a = printAudit\('uses-responsive-images', 'RESPONSIVE IMAGES'\);
  if \(a?.details?.items?.length\) {
    for \(const item of a.details.items.slice\(0, 10\)\) console.log\('  [' + \(item.wastedBytes/1024\).toFixed\(1\) + ' kB wasted] ' + \(item.url||''\).slice\(0, 110\)\);
  } else console.log\('  No issues found.'\);
}

{
  const a = printAudit\('modern-image-formats', 'MODERN IMAGE FORMATS'\);
  if \(a?.details?.items?.length\) {
    for \(const item of a.details.items.slice\(0, 10\)\) console.log\('  [' + \(item.wastedBytes/1024\).toFixed\(1\) + ' kB savings] ' + \(item.url||''\).slice\(0, 110\)\);
  } else console.log\('  No issues found.'\);
}

console.log\('\\n' + '#'.repeat\(80\)\);
console.log\('  WATERFALL NARRATIVE: Navigation Start -> LCP'\);
console.log\('#'.repeat\(80\)\);
const ttfb = audits['server-response-time']?.numericValue;
const fcp = audits['first-contentful-paint']?.numericValue;
const lcp = audits['largest-contentful-paint']?.numericValue;
const si = audits['speed-index']?.numericValue;
const tbt = audits['total-blocking-time']?.numericValue;
const cls = audits['cumulative-layout-shift']?.numericValue;
console.log\('  0ms --- Navigation Start'\);
console.log\('  ' + ttfb?.toFixed\(0\) + 'ms --- TTFB'\);
console.log\('  ' + fcp?.toFixed\(0\) + 'ms --- FCP'\);
console.log\('  ' + lcp?.toFixed\(0\) + 'ms --- LCP'\);
console.log\('  ' + si?.toFixed\(0\) + 'ms --- Speed Index'\);
console.log\('  TBT: ' + tbt?.toFixed\(0\) + 'ms  CLS: ' + cls?.toFixed\(4\)\);
console.log\('  Gap: 0->TTFB=' + ttfb?.toFixed\(0\) + 'ms  TTFB->FCP=' + \(fcp-ttfb\)?.toFixed\(0\) + 'ms  FCP->LCP=' + \(lcp-fcp\)?.toFixed\(0\) + 'ms  Total=' + lcp?.toFixed\(0\) + 'ms'\);

{
  const a = audits['resource-summary'];
  if \(a?.details?.items\) {
    printAudit\('resource-summary', 'RESOURCE SUMMARY'\);
    for \(const item of a.details.items\) console.log\('  ' + \(item.label||'?'\).padEnd\(20\) + ' count=' + String\(item.requestCount\).padStart\(3\) + '  size=' + \(item.transferSize/1024\).toFixed\(1\).padStart\(8\) + ' kB'\);
  }
}

console.log\('\\n[Analysis complete]'\);
"@
Set-Content -Path 'C:\\Users\\trs35\\OneDrive\\Desktop\\clearedge-website\\lh-analyze.mjs' -Value $script -Encoding UTF8
Write-Host "Script written successfully, size: $\(\(Get-Item 'C:\\Users\\trs35\\OneDrive\\Desktop\\clearedge-website\\lh-analyze.mjs'\).Length\) bytes"
PSEOF)
